"  body {
    @apply bg-background text-foreground;
    background: linear-gradient(to bottom, #c9e2ff 0%, #eef6ff 50%, #f9fbff 100%) !important;
    background-attachment: fixed !important;
  }

  body.dark,
  .dark body {
    background: linear-gradient(to bottom, #060b13 0%, #0d1527 60%, #172237 100%) !important;
    background-attachment: fixed !important;
  }"

".blend-custom-icon {
  filter: grayscale(100%) brightness(60%) contrast(300%);
  mix-blend-mode: multiply;
}

.dark .blend-custom-icon {
  filter: grayscale(100%) invert(100%) brightness(130%) contrast(200%);
  mix-blend-mode: screen;
}"

"/* Island masking to blend with sky background */
.island-mask {
  mask-image: linear-gradient(to bottom, transparent 0%, rgba(0, 0, 0, 0.3) 15%, black 45%);
  -webkit-mask-image: linear-gradient(to bottom, transparent 0%, rgba(0, 0, 0, 0.3) 15%, black 45%);
}"

